{
  "sentences": [
    {
      "text": "你必須準時到公司。",
      "pinyin": "Nǐ bìxū zhǔnshí dào gōngsī.",
      "pinyin_numeric": "ni3 bi4xu1 zhun3shi2 dao4 gong1si1",
      "translation_en": "You must arrive at the company on time.",
      "translation_ko": "당신은 회사에 정시에 도착해야 합니다."
    },
    {
      "text": "我們必須遵守規定。",
      "pinyin": "Wǒmen bìxū zūnshǒu guīdìng.",
      "pinyin_numeric": "wo3men bi4xu1 zun1shou3 gui1ding4",
      "translation_en": "We must follow the rules.",
      "translation_ko": "우리는 규정을 지켜야 합니다."
    },
    {
      "text": "你必須帶悠遊卡。",
      "pinyin": "Nǐ bìxū dài yōuyóukǎ.",
      "pinyin_numeric": "ni3 bi4xu1 dai4 you1you2ka3",
      "translation_en": "You must bring your EasyCard.",
      "translation_ko": "당신은 유유카드를 가져와야 합니다."
    },
    {
      "text": "他必須吃藥。",
      "pinyin": "Tā bìxū chī yào.",
      "pinyin_numeric": "ta1 bi4xu1 chi1 yao4",
      "translation_en": "He must take medicine.",
      "translation_ko": "그는 약을 먹어야 합니다."
    },
    {
      "text": "我必須去銀行。",
      "pinyin": "Wǒ bìxū qù yínháng.",
      "pinyin_numeric": "wo3 bi4xu1 qu4 yin2hang2",
      "translation_en": "I must go to the bank.",
      "translation_ko": "나는 은행에 가야 합니다."
    },
    {
      "text": "你必須說中文。",
      "pinyin": "Nǐ bìxū shuō Zhōngwén.",
      "pinyin_numeric": "ni3 bi4xu1 shuo1 Zhong1wen2",
      "translation_en": "You must speak Chinese.",
      "translation_ko": "당신은 중국어를 말해야 합니다."
    },
    {
      "text": "我們必須等十分鐘。",
      "pinyin": "Wǒmen bìxū děng shí fēnzhōng.",
      "pinyin_numeric": "wo3men bi4xu1 deng3 shi2 fen1zhong1",
      "translation_en": "We must wait for ten minutes.",
      "translation_ko": "우리는 10분을 기다려야 합니다."
    },
    {
      "text": "你必須帶雨傘。",
      "pinyin": "Nǐ bìxū dài yǔsǎn.",
      "pinyin_numeric": "ni3 bi4xu1 dai4 yu3san3",
      "translation_en": "You must bring an umbrella.",
      "translation_ko": "당신은 우산을 가져와야 합니다."
    },
    {
      "text": "他必須休息。",
      "pinyin": "Tā bìxū xiūxí.",
      "pinyin_numeric": "ta1 bi4xu1 xiu1xi2",
      "translation_en": "He must rest.",
      "translation_ko": "그는 쉬어야 합니다."
    },
    {
      "text": "我必須做功課。",
      "pinyin": "Wǒ bìxū zuò gōngkè.",
      "pinyin_numeric": "wo3 bi4xu1 zuo4 gong1ke4",
      "translation_en": "I must do homework.",
      "translation_ko": "나는 숙제를 해야 합니다."
    }
  ]
}
